import './dashboard.css';
import logo from "../assets/images/logo.png";
function Dashboard() {
    return (
        <div className='dashboard'>
            <div className="sideBar">
                <div className="logo sideBtn">
                    <img src={logo}/>
                </div>
                <div className="sideBtn">
                    <img src={logo}/><span>Dashboard</span>
                </div>
                <div className="sideBtn">
                    <img src={logo}/><span>User</span>
                </div>
                <div className="sideBtn">
                    <img src={logo}/><span>Product</span>
                </div>
                <div className="sideBtn">
                    <img src={logo}/><span>Blog</span>
                </div>
            </div>
            <div className='main'>
                
            </div>
        </div>
    );
}
export default Dashboard;